const base='https://services.leadconnectorhq.com';
const token=process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_PRIVATE_INTEGRATION_TOKEN||process.env.GHL_TOKEN;
const loc=process.env.GHL_LOCATION_ID_TJB||process.env.GHL_LOCATION_ID||'TW8JsPW5NMnA3tfK2XLn';
if(!token){console.error('NO_TOKEN');process.exit(2)}
const h={Authorization:'Bearer '+token,Version:'2021-07-28','Content-Type':'application/json'};
const req=(m,p,b)=>fetch(base+p,{method:m,headers:h,body:b?JSON.stringify(b):undefined}).then(async r=>({status:r.status,body:JSON.parse(await r.text())}));
(async()=>{
 const contactsR=await req('GET',`/contacts/?locationId=${loc}&limit=100`);
 const oppR=await req('POST','/opportunities/search',{locationId:loc,limit:500});
 const pipesR=await req('GET',`/opportunities/pipelines?locationId=${loc}`);
 const wfR=await req('GET',`/workflows/?locationId=${loc}`);
 const contacts=contactsR.body.contacts||[];
 const opps=oppR.body.opportunities||[];
 const pipes=(pipesR.body.pipelines||[]);
 const stageMap={};
 for(const p of pipes){for(const s of (p.stages||[])){stageMap[s.id]={pipeline:p.name,stage:s.name};}}
 const tagCount={};
 for(const c of contacts){for(const t of (c.tags||[])){tagCount[t]=(tagCount[t]||0)+1}}
 const leads=contacts.length;
 const ebook=tagCount['ebook-buyer']||0;
 const course=tagCount['course-buyer']||0;
 const intensive=tagCount['high-ticket-prospect']||0;
 const conv={lead_to_ebook: leads?ebook/leads*100:0, ebook_to_course: ebook?course/ebook*100:0, course_to_high_ticket: course?intensive/course*100:0};
 let pipelineValue=0;
 const byStage={};
 for(const o of opps){const val=Number(o.monetaryValue||0); pipelineValue+=val; const sid=o.pipelineStageId||'unknown'; if(!byStage[sid]) byStage[sid]={count:0,value:0,name:stageMap[sid]?.stage||sid,pipeline:stageMap[sid]?.pipeline||'unknown'}; byStage[sid].count++; byStage[sid].value+=val; }
 const topStages=Object.values(byStage).sort((a,b)=>b.value-a.value);
 // crude open-rate availability check
 const emailMetricsPaths=['/emails/campaigns?locationId='+loc,'/reporting/email?locationId='+loc,'/campaigns/?locationId='+loc];
 const emailChecks=[];
 for(const p of emailMetricsPaths){const r=await fetch(base+p,{headers:h}); emailChecks.push({path:p,status:r.status});}
 const out={
   locationId:loc,
   instances:[{name:'Truth J Blue — Primary SaaS',locationId:loc}],
   counts:{contacts:contacts.length,opportunities:opps.length,workflows:(wfR.body.workflows||[]).length},
   tagCount,
   conversionRates:conv,
   pipelineValue,
   topStages,
   emailMetricAccess:emailChecks,
   timestamp:new Date().toISOString()
 };
 console.log(JSON.stringify(out,null,2));
})();
